            "name": "create",
            "arguments": {
              "file_text": "// Regression tests for the prompt-classification heuristics in classifier.mjs.\n// Run with: node --test .github/extensions/model-router/classifier.test.mjs\n\nimport { describe, it } from \"node:test\";\nimport assert from \"node:assert/strict\";\nimport {\n  normalizePrompt,\n  matchesPattern,\n  isExplicitReviewRequest,\n  isToolHeavy,\n  isComplexOrchestration,\n  classifyPrompt,\n} from \"./classifier.mjs\";\n\n// ---------------------------------------------------------------------------\n// normalizePrompt\n// ---------------------------------------------------------------------------\ndescribe(\"normalizePrompt\", () => {\n  it(\"lowercases input\", () => {\n    assert.equal(normalizePrompt(\"Hello World\"), \"hello world\");\n  });\n\n  it(\"coerces non-string gracefully\", () => {\n    assert.equal(normalizePrompt(null), \"\");\n    assert.equal(normalizePrompt(undefined), \"\");\n    assert.equal(normalizePrompt(42), \"42\");\n  });\n});\n\n// ---------------------------------------------------------------------------\n// matchesPattern — word-boundary accuracy\n// ---------------------------------------------------------------------------\ndescribe(\"matchesPattern (word boundaries)\", () => {\n  it(\"matches a standalone keyword\", () => {\n    assert.ok(matchesPattern(\"please fix the bug\", \"fix\"));\n  });\n\n  it('does NOT match \"fix\" inside \"prefix\"', () => {\n    assert.ok(!matchesPattern(\"prefix this value\", \"fix\"));\n  });\n\n  it('does NOT match \"call\" inside \"callback\"', () => {\n    assert.ok(!matchesPattern(\"register a callback here\", \"call\"));\n  });\n\n  it('does NOT match \"run\" inside \"return\"', () => {\n    assert.ok(!matchesPattern(\"make it return early\", \"run\"));\n  });\n\n  it(\"multi-word phrases use substring matching (no boundary requirement)\", () => {\n    assert.ok(matchesPattern(\"find bugs in the codebase\", \"find bugs\"));\n  });\n\n  it(\"multi-word phrase: negative when absent\", () => {\n    assert.ok(!matchesPattern(\"find all functions\", \"find bugs\"));\n  });\n});\n\n// ---------------------------------------------------------------------------\n// isExplicitReviewRequest\n// ---------------------------------------------------------------------------\ndescribe(\"isExplicitReviewRequest\", () => {\n  const positive = [\n    \"please review this PR\",\n    \"Can you do a code review of my changes?\",\n    \"Review the code in src/auth.ts\",\n    \"audit the authentication module\",\n    \"check approval readiness before merging\",\n    \"approve this pull request\",\n    \"PR review needed\",\n    \"find bugs in the payment service\",\n    \"bug finding session on the new feature\",\n    \"regression hunting after the deploy\",\n    \"regression hunt before release\",\n    \"find regressions introduced in v2\",\n  ];\n\n  for (const prompt of positive) {\n    it(`detects explicit review: \"${prompt.slice(0, 60)}\"`, () => {\n      assert.ok(\n        isExplicitReviewRequest(normalizePrompt(prompt)),\n        `Expected review detection for: ${prompt}`,\n      );\n    });\n  }\n\n  const negative = [\n    \"implement the new login flow\",\n    \"update the README\",\n    \"debug the crash in production\",\n    \"write a plan for the migration\",\n    \"explain how the router works\",\n    // \"review\" must not trigger on unrelated word-boundary neighbors:\n    \"I need to preview the changes\",\n    // \"fix\" alone is debugging, not review:\n    \"fix the null pointer exception\",\n  ];\n\n  for (const prompt of negative) {\n    it(`does NOT flag as review: \"${prompt.slice(0, 60)}\"`, () => {\n      assert.ok(\n        !isExplicitReviewRequest(normalizePrompt(prompt)),\n        `Unexpected review detection for: ${prompt}`,\n      );\n    });\n  }\n});\n\n// ---------------------------------------------------------------------------\n// isToolHeavy\n// ---------------------------------------------------------------------------\ndescribe(\"isToolHeavy\", () => {\n  it(\"detects bash keyword\", () => {\n    assert.ok(isToolHeavy(\"run the bash script to deploy\"));\n  });\n\n  it(\"detects curl\", () => {\n    assert.ok(isToolHeavy(\"use curl to hit the endpoint\"));\n  });\n\n  it(\"detects api (case-insensitive via normalizePrompt)\", () => {\n    assert.ok(isToolHeavy(normalizePrompt(\"call the REST API\")));\n  });\n\n  it(\"detects agent keyword\", () => {\n    assert.ok(isToolHeavy(\"launch an agent to scrape the page\"));\n  });\n\n  it(\"is false for pure prose\", () => {\n    assert.ok(!isToolHeavy(\"explain what dependency injection means\"));\n  });\n});\n\n// ---------------------------------------------------------------------------\n// isComplexOrchestration\n// ---------------------------------------------------------------------------\ndescribe(\"isComplexOrchestration\", () => {\n  const positive = [\n    \"run parallel agents to process each file\",\n    \"coordinate multiple agents for the migration\",\n    \"use a multi-agent setup to handle the pipeline\",\n    \"orchestrate the deployment across regions\",\n    \"set up orchestration for the CI workflow\",\n    \"use parallel tools to speed up the analysis\",\n    \"build a tool chain that clones then tests then deploys\",\n    \"chained tools across the pipeline stages\",\n  ];\n\n  for (const prompt of positive) {\n    it(`detects orchestration: \"${prompt.slice(0, 60)}\"`, () => {\n      assert.ok(\n        isComplexOrchestration(normalizePrompt(prompt)),\n        `Expected orchestration for: ${prompt}`,\n      );\n    });\n  }\n\n  const negative = [\n    \"implement a simple REST endpoint\",\n    \"write unit tests for the auth module\",\n    \"refactor the login function\",\n    \"run the test suite\",\n  ];\n\n  for (const prompt of negative) {\n    it(`does NOT flag as orchestration: \"${prompt.slice(0, 60)}\"`, () => {\n      assert.ok(\n        !isComplexOrchestration(normalizePrompt(prompt)),\n        `Unexpected orchestration for: ${prompt}`,\n      );\n    });\n  }\n});\n\n// ---------------------------------------------------------------------------\n// classifyPrompt — explicit review → reasoning tier\n// ---------------------------------------------------------------------------\ndescribe(\"classifyPrompt: explicit review detection\", () => {\n  it(\"review keyword → kind=review, tier=reasoning\", () => {\n    const r = classifyPrompt(\"Please review this PR before merging\");\n    assert.equal(r.kind, \"review\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"audit keyword → kind=review, tier=reasoning\", () => {\n    const r = classifyPrompt(\"Audit the security module for vulnerabilities\");\n    assert.equal(r.kind, \"review\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"find bugs → kind=review, tier=reasoning\", () => {\n    const r = classifyPrompt(\"Find bugs in the new payment flow\");\n    assert.equal(r.kind, \"review\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"regression hunt → kind=review, tier=reasoning\", () => {\n    const r = classifyPrompt(\"Do a regression hunt across the last three releases\");\n    assert.equal(r.kind, \"review\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"review beats implement keyword — review wins\", () => {\n    // A prompt that has both \"implement\" and \"review\" should still route to review\n    const r = classifyPrompt(\"implement and review the auth module\");\n    assert.equal(r.kind, \"review\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n});\n\n// ---------------------------------------------------------------------------\n// classifyPrompt — tool-heavy implementation → builder tier\n// ---------------------------------------------------------------------------\ndescribe(\"classifyPrompt: tool-heavy implementation routing\", () => {\n  it(\"simple implement → builder (default)\", () => {\n    const r = classifyPrompt(\"implement the user registration endpoint\");\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"builder\");\n  });\n\n  it(\"implement + bash → builder, toolHeavy=true\", () => {\n    const r = classifyPrompt(\"implement a bash script that backs up the database\");\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"builder\");\n    assert.equal(r.toolHeavy, true);\n  });\n\n  it(\"implement + curl + api → builder, toolHeavy=true\", () => {\n    const r = classifyPrompt(\"implement a curl wrapper for the payments API\");\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"builder\");\n    assert.equal(r.toolHeavy, true);\n  });\n\n  it(\"build + agent keyword → builder (tool escalates complexity but not to reasoning on its own)\", () => {\n    const r = classifyPrompt(\"build a function that calls an agent\");\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"builder\");\n    assert.equal(r.toolHeavy, true);\n  });\n\n  it(\"pure light implement (show/list + no complexity) → economy\", () => {\n    // \"list\" is both a LIGHT_KEYWORD and overlaps with IMPLEMENT (via \"find\" which isn't impl)\n    // \"show\" is light — combined with zero complexity should stay economy\n    const r = classifyPrompt(\"show me what to add\");\n    // \"show\" → light, \"add\" → implement; but LIGHT_KEYWORDS wins when complexity=0\n    assert.equal(r.tier, \"economy\");\n  });\n});\n\n// ---------------------------------------------------------------------------\n// classifyPrompt — orchestration escalation → reasoning tier\n// ---------------------------------------------------------------------------\ndescribe(\"classifyPrompt: orchestration escalation\", () => {\n  it(\"implement + parallel agents → reasoning\", () => {\n    const r = classifyPrompt(\n      \"implement a workflow using parallel agents to process each repository\",\n    );\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"implement + orchestrate → reasoning\", () => {\n    const r = classifyPrompt(\"implement and orchestrate the multi-step deployment pipeline\");\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"implement + tool chain → reasoning\", () => {\n    const r = classifyPrompt(\"build a tool chain that lints, tests, and deploys\");\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"implement + chained tools → reasoning\", () => {\n    const r = classifyPrompt(\"write a script using chained tools to process the data\");\n    assert.equal(r.kind, \"implementation\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"general prompt + orchestration → reasoning\", () => {\n    const r = classifyPrompt(\n      \"set up multi-agent orchestration for the analytics pipeline\",\n    );\n    // \"set up\" isn't an implement keyword, but orchestration escalates general→reasoning\n    assert.equal(r.tier, \"reasoning\");\n  });\n\n  it(\"plain implement WITHOUT orchestration stays builder\", () => {\n    const r = classifyPrompt(\"implement a retry mechanism for failed HTTP requests\");\n    assert.equal(r.tier, \"builder\");\n  });\n});\n\n// ---------------------------------------------------------------------------\n// classifyPrompt — misc tier boundaries\n// ---------------------------------------------------------------------------\ndescribe(\"classifyPrompt: tier boundaries\", () => {\n  it(\"plain question → lightweight, economy\", () => {\n    const r = classifyPrompt(\"what is dependency injection?\");\n    assert.equal(r.kind, \"lightweight\");\n    assert.equal(r.tier, \"economy\");\n  });\n\n  it(\"debug keyword alone → debugging, builder (low complexity)\", () => {\n    const r = classifyPrompt(\"debug the login crash\");\n    assert.equal(r.kind, \"debugging\");\n    assert.equal(r.tier, \"builder\");\n  });\n\n  it(\"plan keyword alone → planning, builder (low complexity)\", () => {\n    const r = classifyPrompt(\"plan the database migration\");\n    assert.equal(r.kind, \"planning\");\n    assert.equal(r.tier, \"builder\");\n  });\n\n  it(\"review always wins over planning keyword in same prompt\", () => {\n    const r = classifyPrompt(\"review and plan the architecture changes\");\n    assert.equal(r.kind, \"review\");\n    assert.equal(r.tier, \"reasoning\");\n  });\n});\n",
